mapper.select:
SELECT c.id, c.course_code, c.course_name, d.dept_name, c.credit, c.course_type, c.semester, COUNT(cr.id) AS class_count FROM course c LEFT JOIN sys_dept d ON c.dept_id = d.id LEFT JOIN class_room cr ON cr.course_id = c.id AND cr.is_deleted = 0 WHERE c.is_deleted = 0
AND c.semester = #{semester}
AND c.dept_id = #{deptId}
AND (c.course_name LIKE CONCAT('%', #{keyword}, '%') OR c.course_code LIKE CONCAT('%', #{keyword}, '%'))
GROUP BY c.id, c.course_code, c.course_name, d.dept_name, c.credit, c.course_type, c.semester ORDER BY c.semester DESC, c.course_name ASC
